def categories_from_path(special_dir)
      if relative_path.start_with?(special_dir)
        superdirs = []
      else
        superdirs = relative_path.sub(Document.superdirs_regex(special_dir), "")
        superdirs = superdirs.split(File::SEPARATOR)
        superdirs.reject! { |c| c.empty? || c == special_dir || c == basename }
      end

      merge_data!({ "categories" => superdirs }, :source => "file path")
    end

def pg_class_relname(type, opts)
        ds = metadata_dataset.from(:pg_class).where(:relkind=>type).select(:relname).server(opts[:server]).join(:pg_namespace, :oid=>:relnamespace)
        ds = filter_schema(ds, opts)
        m = output_identifier_meth
        if defined?(yield)
          yield(ds)
        elsif opts[:qualify]
          ds.select_append{pg_namespace[:nspname]}.map{|r| Sequel.qualify(m.call(r[:nspname]).to_s, m.call(r[:relname]).to_s)}
        else
          ds.map{|r| m.call(r[:relname])}
        end
      end

def self.configure(model, opts=OPTS)
        model.instance_exec do
          @allow_manual_timestamp_update = opts[:allow_manual_update]||false
          @create_timestamp_field = opts[:create]||:created_at
          @update_timestamp_field = opts[:update]||:updated_at
          @create_timestamp_overwrite = opts[:force]||false
          @set_update_timestamp_on_create = opts[:update_on_create]||false
        end
      end

def fetch(record_ids)
        records = @model_class.where(@find_by => record_ids)
        record_lookup = {}
        if @find_by_many
          records.each do |r|
            key = @find_by.map { |fb| r.public_send(fb) }
            record_lookup[key] = r
          end
        else
          records.each { |r| record_lookup[r.public_send(@find_by)] = r }
        end
        record_ids.map { |id| record_lookup[id] }
      end
